                    value={varianceValue} 
                    subtext="Active Case Impact" 
                    icon={DollarSign} 
                    color="emerald" 
                />
            </div>
            <div key="metric-risks">
                <NexMetricItem 
                    onClick={() => navigateTo('inbox', undefined, 'Critical')} 
