const Breadcrumbs = ({ nav }: { nav: { view: ViewState, selectedId?: string } }) => {
    const { addNotification } = useBPM();
    const copyId = () => {
        if(nav.selectedId) {
            navigator.clipboard.writeText(nav.selectedId);
            addNotification('info', `Copied ID: ${nav.selectedId}`);
        }
    };

    const getViewName = (v: string) => v.charAt(0).toUpperCase() + v.slice(1).replace(/-/g, ' ');
    const parentMap: Record<string, ViewState> = {
        'case-viewer': 'cases', 'create-case': 'cases', 'edit-case': 'cases',
        'form-designer': 'forms', 'edit-user': 'identity', 'create-user': 'identity',
        'create-role': 'identity', 'edit-role': 'identity',
    };
    const parent = parentMap[nav.view];

    return (
        <div 
          className="flex items-center gap-2 py-2 bg-subtle border-b border-default text-xs text-secondary shrink-0 px-layout"
